        // Brute-force all possible ternary masks
        long long max_mask = 1;
        for (int i = 0; i < n; ++i) {
            max_mask *= 3;
        }

        for (long long mask = 0; mask < max_mask; ++mask) {
            vector<long long> A, B, C;
            long long current = mask;
            for (int i = 0; i < n; ++i) {
                int rem = current % 3;
                current /= 3;
                if (rem == 0) {
                    A.push_back(nums[i]);
                } else if (rem == 1) {
                    B.push_back(nums[i]);
                } else {
                    C.push_back(nums[i]);
                }
            }

            long long xorA = 0;
            for (long long num : A) {
                xorA ^= num;
            }

            long long andB = (B.empty() ? 0 : ~0LL);
            for (long long num : B) {
                andB &= num;
            }

            long long xorC = 0;
            for (long long num : C) {
                xorC ^= num;
            }

            long long sum = xorA + andB + xorC;
            if (sum > max_sum) {
                max_sum = sum;
