                    if (i != a && i != b) {
                        C.push_back(nums[i]);
                    }
                }
                long long xorC = 0;
                for (long long num : C) {
                    xorC ^= num;
                }
                long long sum = xorA + andB + xorC;
                if (sum > max_sum) {
                    max_sum = sum;
                }
            }

            for (int b1 = 0; b1 < n; ++b1) {
                if (b1 == a) continue;
                for (int b2 = b1 + 1; b2 < n; ++b2) {
                    if (b2 == a) continue;
                    // B has two elements
                    vector<long long> B = {nums[b1], nums[b2]};
                    long long andB = nums[b1] & nums[b2];

                    vector<long long> C;
