                        if (i != a && i != b1 && i != b2) {
                            C.push_back(nums[i]);
                        }
                    }
                    long long xorC = 0;
                    for (long long num : C) {
                        xorC ^= num;
                    }
                    long long sum = xorA + andB + xorC;
                    if (sum > max_sum) {
                        max_sum = sum;
                    }
                }
            }
        }

        // Also try A empty, B has one or two elements
        for (int b = 0; b < n; ++b) {
            // B has one element
            vector<long long> B = {nums[b]};
            long long andB = nums[b];

            vector<long long> C;
            for (int i = 0; i < n; ++i) {
                if (i != b) {
                    C.push_back(nums[i]);
                }
            }
            long long xorC = 0;
            for (long long num : C) {
                xorC ^= num;
            }
            long long sum = 0 + andB + xorC;
            if (sum > max_sum) {
                max_sum = sum;
            }
        }

        for (int b1 = 0; b1 < n; ++b1) {
            for (int b2 = b1 + 1; b2 < n; ++b2) {
                // B has two elements
                vector<long long> B = {nums[b1], nums[b2]};
                long long andB = nums[b1] & nums[b2];

                vector<long long> C;
                for (int i = 0; i < n; ++i) {
                    if (i != b1 && i != b2) {
