                    .fold(0, |acc, (_, &x)| acc ^ x);
                let sum = 0 + and_b + xor_c;
                if sum > max_sum {
                    max_sum = sum;
                }
            }
        }

        // Also try A and B empty
        let xor_c = nums.iter().fold(0, |acc, &x| acc ^ x);
        let sum = 0 + 0 + xor_c;
        if sum > max_sum {
            max_sum = sum;
        }
    }

    max_sum
